class Solution {
public:
    bool equalFrequency(string word) {
        unordered_map<char, int> freq;
        for (char c : word) freq[c]++;

        unordered_map<int, int> count;
        for (auto& f : freq) count[f.second]++;

        if (count.size() == 1) {
            int f = freq.begin()->second;
            return f == 1 || count[f - 1] == 1;
        }

        if (count.size() != 2) return false;

        auto it = count.begin();
        int f1 = it->first, c1 = it->second;
        it++;
        int f2 = it->first, c2 = it->second;

        return (f1 == 1 && c1 == 1) || (f2 == 1 && c2 == 1) || (f1 - 1 == f2 && c2 == 1) || (f2 - 1 == f1 && c1 == 1);
    }
};
